// Bundles disks/gmc64-demo.d64 as a base64-encoded JS file at
// js/demo-disk-source.js. The editor loads this via <script> on every
// boot so autoLoadDemo() can decode and insert the disk without a
// network fetch — making the "boot into demo" experience work from
// file:// too (CORS blocks fetch under the null origin, even for
// same-folder files).
//
// Re-run after editing disks/gmc64-demo.d64:
//     node tools/bundle-demo-disk.js
// (CI / test suite verifies the bundle is current; see
// tests/demo-bundle.test.js.)

import { readFileSync, writeFileSync } from 'fs';
import { resolve, dirname } from 'path';
import { fileURLToPath } from 'url';

const __filename = fileURLToPath(import.meta.url);
const __dirname = dirname(__filename);
const ROOT = resolve(__dirname, '..');

const HEADER = `// AUTO-GENERATED by tools/bundle-demo-disk.js — do not edit by hand.
// Regenerate after editing disks/gmc64-demo.d64.
`;

export function generate() {
    const diskBytes = readFileSync(resolve(ROOT, 'disks/gmc64-demo.d64'));
    const base64 = diskBytes.toString('base64');
    return HEADER + `globalThis._demoDiskBase64 = "${base64}";\n`;
}

// CLI: write the bundle to disk.
if (import.meta.url === `file://${process.argv[1]}`) {
    const out = generate();
    const target = resolve(ROOT, 'js', 'demo-disk-source.js');
    writeFileSync(target, out);
    console.log(`wrote ${target} (${out.length.toLocaleString()} bytes)`);
}
